queries.sparql:
PREFIX : <http://ambrosia.example.org/construction#>
PREFIX p: <http://ambrosia.example.org/construction/prop#>
SELECT ?mv WHERE { ?p a :Projects ; p:Monetary_Value ?mv ; p:durationDays ?d . { SELECT (MAX(?d2) AS ?mx) WHERE { ?q a :Projects ; p:durationDays ?d2 } } FILTER(?d = ?mx) }

