PREFIX p: <http://ambrosia.example.org/construction/prop#>
CHOICE vague {
  component: { SELECT ?mv WHERE { ?p a :Projects ; p:Monetary_Value ?mv ; p:durationDays ?d . { SELECT (MAX(?d2) AS ?mx) WHERE { ?q a :Projects ; p:durationDays ?d2 } } FILTER(?d = ?mx) } }
  component_2: { SELECT ?pb WHERE { ?p a :Projects ; p:Percentage_Of_Budget ?pb ; p:durationDays ?d . { SELECT (MAX(?d2) AS ?mx) WHERE { ?q a :Projects ; p:durationDays ?d2 } } FILTER(?d = ?mx) } }
  full: { SELECT ?mv ?pb WHERE { ?p a :Projects ; p:Monetary_Value ?mv ; p:Percentage_Of_Budget ?pb ; p:durationDays ?d . { SELECT (MAX(?d2) AS ?mx) WHERE { ?q a :Projects ; p:durationDays ?d2 } } FILTER(?d = ?mx) } }
}

PREFIX : <http://ambrosia.example.org/construction#>
PREFIX p: <http://ambrosia.example.org/construction/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE vague {
  full: { SELECT ?monetary_value ?percentage_of_budget WHERE {
  ?project a :Projects .
  ?project p:Monetary_Value ?monetary_value .
  ?project p:Percentage_Of_Budget ?percentage_of_budget .
  ?project p:Infrastructure ?infrastructure_f .
  FILTER(?infrastructure_f = "Residential Building")
} }
  component: { SELECT ?monetary_value WHERE {
  ?project a :Projects .
  ?project p:Monetary_Value ?monetary_value .
  ?project p:Infrastructure ?infrastructure_f .
  FILTER(?infrastructure_f = "Residential Building")
} }
  component_2: { SELECT ?percentage_of_budget WHERE {
  ?project a :Projects .
  ?project p:Percentage_Of_Budget ?percentage_of_budget .
  ?project p:Infrastructure ?infrastructure_f .
  FILTER(?infrastructure_f = "Residential Building")
} }
}
